{"path": "/tmp/sv-0558ebb6d1bb4cf7866aacf09e8e596f/Components/Catalog/CatalogPagination.razor", "file_text": "<nav aria-label="Product catalog pagination">
    <ul class="pagination justify-content-center mb-0">
        <li class="page-item @(Page <= 1 ? "disabled" : "")">
            <button class="page-link" @onclick="() => OnPageChanged.InvokeAsync(Page - 1)" disabled="@(Page <= 1)">
                Previous
            </button>
        </li>
        @foreach (var p in GetPageNumbers())
        {
            <li class="page-item @(p == Page ? "active" : "")">
                <button class="page-link" @onclick="() => OnPageChanged.InvokeAsync(p)">@p</button>
            </li>
        }
        <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
            <button class="page-link" @onclick="() => OnPageChanged.InvokeAsync(Page + 1)" disabled="@(Page >= TotalPages)">
                Next
            </button>
        </li>
    </ul>
</nav>

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, Page - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}
"}

