@using sv_0558ebb6d1bb4cf7866aacf09e8e596f.Services
@using sv_0558ebb6d1bb4cf7866aacf09e8e596f.Components.Catalog
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Sidebar *@
    <div class="col-md-3">
        <CatalogSidebar Categories="_categories"
                        OnApplyFilters="HandleApplyFilters"
                        OnClearFilters="HandleClearFilters" />
    </div>

    @* Main content *@
    <div class="col-md-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-link p-0 ms-2" @onclick="LoadProductsAsync">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading products…</span>
                </div>
                <span class="ms-2">Loading products…</span>
            </div>
        }
        else if (_result is not null && _result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else if (_result is not null)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_result.Page"
                            PageSize="_result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (TotalPages > 1)
            {
                <div class="mt-4">
                    <CatalogPagination Page="_result.Page"
                                       TotalPages="TotalPages"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
    </div>
</div>

@code {
    /// <summary>Raised when a product card is clicked so a parent can navigate to the detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private const int PageSize = 12;

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadProductsAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with a cart service when available
        return Task.CompletedTask;
    }
}
"}

